const now = new Date();
now.setDate(1);
now.setDate(0);

const prevMonth = now.getMonth() + 1;
const prevYear  = now.getFullYear();

const monthNames = ['January','February','March','April','May','June',
                    'July','August','September','October','November','December'];
const monthName = monthNames[prevMonth - 1];

return [{ json: { prevMonth, prevYear, monthName, reportPeriod: `${monthName} ${prevYear}` } }];

const periodData   = $('2. Code — Get Previous Month').first().json;
const prevMonth    = parseInt(periodData.prevMonth);
const prevYear     = parseInt(periodData.prevYear);
const reportPeriod = periodData.reportPeriod;

const incomeRows = $('3. Google Sheets — Get Income Data').all()
  .filter(i => parseInt(i.json.Month) === prevMonth && parseInt(i.json.Year) === prevYear);

const expenseRows = $('4. Google Sheets — Get Expense Data').all()
  .filter(i => parseInt(i.json.Month) === prevMonth && parseInt(i.json.Year) === prevYear);

if (incomeRows.length === 0 && expenseRows.length === 0) {
  throw new Error(`No financial data found for ${reportPeriod}. Add rows with Month=${prevMonth} and Year=${prevYear} to your Google Sheet.`);
}

const incomeDetail = incomeRows.map(i => ({
  category: i.json.Category || 'Other Income',
  budget:   parseFloat(i.json.Budget)  || 0,
  actual:   parseFloat(i.json.Actual)  || 0
}));

const totalIncomeBudget = incomeDetail.reduce((s, r) => s + r.budget, 0);
const totalIncomeActual = incomeDetail.reduce((s, r) => s + r.actual, 0);
const incomeVariance    = totalIncomeActual - totalIncomeBudget;

const cogsRows = expenseRows.filter(i => (i.json.Type || '').toUpperCase() === 'COGS');
const opexRows = expenseRows.filter(i => (i.json.Type || '').toUpperCase() !== 'COGS');

const cogsDetail = cogsRows.map(i => ({
  category: i.json.Category || 'Cost of Goods',
  budget:   parseFloat(i.json.Budget) || 0,
  actual:   parseFloat(i.json.Actual) || 0
}));

const opexDetail = opexRows.map(i => ({
  category: i.json.Category || 'Operating Expense',
  budget:   parseFloat(i.json.Budget) || 0,
  actual:   parseFloat(i.json.Actual) || 0
}));

const totalCogsBudget = cogsDetail.reduce((s, r) => s + r.budget, 0);
const totalCogsActual = cogsDetail.reduce((s, r) => s + r.actual, 0);
const totalOpexBudget = opexDetail.reduce((s, r) => s + r.budget, 0);
const totalOpexActual = opexDetail.reduce((s, r) => s + r.actual, 0);

const grossProfitBudget = totalIncomeBudget - totalCogsBudget;
const grossProfitActual = totalIncomeActual - totalCogsActual;
const grossProfitMarginBudget = totalIncomeBudget > 0 ? (grossProfitBudget / totalIncomeBudget * 100).toFixed(1) : 0;
const grossProfitMarginActual = totalIncomeActual > 0 ? (grossProfitActual / totalIncomeActual * 100).toFixed(1) : 0;

const netProfitBudget = grossProfitBudget - totalOpexBudget;
const netProfitActual = grossProfitActual - totalOpexActual;
const netProfitMarginBudget = totalIncomeBudget > 0 ? (netProfitBudget / totalIncomeBudget * 100).toFixed(1) : 0;
const netProfitMarginActual = totalIncomeActual > 0 ? (netProfitActual / totalIncomeActual * 100).toFixed(1) : 0;

const fmt = n => Math.round(n).toLocaleString('en-US');

const buildRows = (rows) => rows
  .map(r => `  ${r.category}: Budget ${fmt(r.budget)} | Actual ${fmt(r.actual)} | Variance ${fmt(r.actual - r.budget)}`)
  .join('\n');

const plText = [
  `REPORT PERIOD: ${reportPeriod}`,
  ``,
  `=== REVENUE ===`,
  buildRows(incomeDetail),
  `TOTAL REVENUE: Budget ${fmt(totalIncomeBudget)} | Actual ${fmt(totalIncomeActual)} | Variance ${fmt(incomeVariance)}`,
  ``,
  `=== COST OF GOODS SOLD ===`,
  cogsDetail.length > 0 ? buildRows(cogsDetail) : '  No COGS entries',
  `TOTAL COGS: Budget ${fmt(totalCogsBudget)} | Actual ${fmt(totalCogsActual)} | Variance ${fmt(totalCogsActual - totalCogsBudget)}`,
  ``,
  `=== GROSS PROFIT ===`,
  `GROSS PROFIT: Budget ${fmt(grossProfitBudget)} | Actual ${fmt(grossProfitActual)} | Variance ${fmt(grossProfitActual - grossProfitBudget)}`,
  `GP MARGIN: Budget ${grossProfitMarginBudget}% | Actual ${grossProfitMarginActual}%`,
  ``,
  `=== OPERATING EXPENSES ===`,
  opexDetail.length > 0 ? buildRows(opexDetail) : '  No operating expenses',
  `TOTAL OPEX: Budget ${fmt(totalOpexBudget)} | Actual ${fmt(totalOpexActual)} | Variance ${fmt(totalOpexActual - totalOpexBudget)}`,
  ``,
  `=== NET PROFIT ===`,
  `NET PROFIT: Budget ${fmt(netProfitBudget)} | Actual ${fmt(netProfitActual)} | Variance ${fmt(netProfitActual - netProfitBudget)}`,
  `NP MARGIN: Budget ${netProfitMarginBudget}% | Actual ${netProfitMarginActual}%`
].join('\n');

return [{
  json: {
    plText,
    reportPeriod,
    prevMonth,
    prevYear,
    totalRevenue:    fmt(totalIncomeActual),
    totalCogs:       fmt(totalCogsActual),
    grossProfit:     fmt(grossProfitActual),
    gpMargin:        grossProfitMarginActual + '%',
    totalOpex:       fmt(totalOpexActual),
    netProfit:       fmt(netProfitActual),
    npMargin:        netProfitMarginActual + '%',
    revenueVariance: fmt(incomeVariance)
  }
}];

let html = $input.first().json.output || '';
html = html.trim()
  .replace(/^```html\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

const plData = $('5. Code — Build P&L Statement').first().json;

return [{
  json: {
    cleanHtml: html,
    reportPeriod:    plData.reportPeriod,
    totalRevenue:    plData.totalRevenue,
    grossProfit:     plData.grossProfit,
    gpMargin:        plData.gpMargin,
    netProfit:       plData.netProfit,
    npMargin:        plData.npMargin,
    revenueVariance: plData.revenueVariance
  }
}];
